code = """import json

# Load funding data directly from storage
funding_records = var_functions.query_db:42

# Load civic documents
civic_file = var_functions.query_db:26
with open(civic_file, 'r') as f:
    civic_docs = json.load(f)

# Build project status map
status_map = {}
for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    section = None
    for line in lines:
        line = line.strip()
        if not line:
            continue
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            section = 'not_started'
        elif section and len(line) > 10 and not line.startswith('(') and 'Updates' not in line and 'Schedule' not in line and 'Page' not in line and 'Project Description' not in line:
            base_name = line.split('(')[0].strip()
            if section == 'construction':
                status_map[base_name] = 'completed'
            else:
                status_map[base_name] = section

# Combine funding and status data
final_results = []
for rec in funding_records:
    project_name = rec['Project_Name']
    base_name = project_name.split('(')[0].strip()
    status = 'unknown'
    
    if base_name in status_map:
        status = status_map[base_name]
    else:
        for key in status_map:
            if base_name.lower() in key.lower() or key.lower() in base_name.lower():
                status = status_map[key]
                break
    
    final_results.append([
        project_name,
        rec['Funding_Source'],
        int(rec['Amount']),
        status
    ])

# Sort by project name
final_results.sort(key=lambda x: x[0])

# Format output
output_list = []
for item in final_results:
    output_list.append('Project: ' + item[0])
    output_list.append('Funding Source: ' + item[1])
    output_list.append('Amount: ' + str(item[2]))
    output_list.append('Status: ' + item[3])
    output_list.append('-' * 70)

result_data = {
    'count': len(final_results),
    'total_funding': sum(item[2] for item in final_results),
    'output': output_list
}

print('__RESULT__:')
print(json.dumps(result_data))"""

